const Navbar = ({ variant = "public" }) => {
  return (
    <div className="navbar">
      <div style={{ fontWeight: 700 }}>
        🧿 RetailVision AI
      </div>

      {variant === "public" && (
        <div>
          <button>Sign In</button>
          <button>Sign Up</button>
        </div>
      )}
    </div>
  );
};
